-- Seed roles and permissions. The bootstrap admin user is created in Java
-- (com.attendance.identity.service.AdminBootstrapper) so the bcrypt hash
-- is generated by the configured PasswordEncoder rather than embedded as a literal.

SET @now = UTC_TIMESTAMP();

-- ---------- roles ----------
SET @role_admin    = UNHEX(REPLACE(UUID(), '-', ''));
SET @role_hr       = UNHEX(REPLACE(UUID(), '-', ''));
SET @role_manager  = UNHEX(REPLACE(UUID(), '-', ''));
SET @role_employee = UNHEX(REPLACE(UUID(), '-', ''));


-- ---------- permissions ----------

-- ADMIN: every permission.
SELECT @role_admin, p.id FROM permission p;

SELECT @role_hr, p.id FROM permission p
WHERE p.code IN ('user.read','employee.read','employee.write','schedule.read','schedule.write',
                 'timecard.read','timecard.edit','leave.read','leave.approve','report.run',
                 'exception.read','exception.resolve','audit.read');

SELECT @role_manager, p.id FROM permission p
WHERE p.code IN ('employee.read','schedule.read','timecard.read','timecard.edit',
                 'leave.read','leave.approve','report.run','exception.read','exception.resolve');

SELECT @role_employee, p.id FROM permission p
WHERE p.code IN ('timecard.read','leave.read');
